# -*- coding: UTF-8 -*-"""Create on 2023-10-17@Author: LiangShubo@email: liangshubo@neusoftmedical.com"""import osimport globimport randomimport pickleimport cv2import numpy as npimport imageioimport torchimport torch.utils.data as data# import SimpleITK as sitkfrom abc import abstractmethodimport osimport randomclass BaseDataset(data.Dataset):    def __init__(self, args, dataset_name=None):        self.dataset_image_pathfile = os.path.join(args.dataset_path, dataset_name, dataset_name + ".txt")        self.image_path_list = []        self.gt_path_list = []        # self.mask_path_list=[]        self.crop_traindata = args.crop_traindata        self.crop_testdata = args.crop_testdata        self.patch_size = args.patch_size        self.argument_scale = args.argument_scale        self.rgb_range = args.rgb_range        self.name = dataset_name        self.light_change = args.light_argument    @abstractmethod    def get_path_from_txt(self):        """        the image and gt filepoath will read from self.dataset_image_pathfile        and save in self.image_path_list\self.gt_path_list        """        raise NotImplementedError    def __len__(self):        return len(self.image_path_list) * self.argument_scale    def __getitem__(self, idx):        idx = idx % len(self.image_path_list)        image = self.image_path_list[idx]        gt = self.gt_path_list[idx]        tensor_image, tensor_gt = self.load_file(image, gt)        return tensor_image, tensor_gt    @abstractmethod    def crop_image(self, image):        '''        the scrop of crop image         '''        raise NotImplementedError    @abstractmethod    def load_file(self, image, gt):        '''        input the image,gt is the pathfile and will load array         and process array include crop and get patch_size and augment_patch         note the process will be control by self.crop_traindata \ self.patch_size \ self.augment_patch        '''        raise NotImplementedError    def np2tensor(self, img):        img = np.ascontiguousarray(img)        tensor = torch.from_numpy(img).float()        tensor = tensor.mul_(self.rgb_range / 255).unsqueeze(            0)  # 若rgb_range = 1 则会乘上1/255 归一化到0-1 ，若是255则会乘上1，则不会归一化到255 范围        return tensor    def get_patch(self, *args, multi=False):        ih, iw = args[0].shape[:2]        hp = self.patch_size        wp = self.patch_size        ix = random.randrange(0, iw - wp + 1)        iy = random.randrange(0, ih - hp + 1)        def _crop(s):            return s[iy:iy + hp, ix:ix + wp]        ret = [_crop(a) for a in args]        return ret    def augment_patch(self, image, mask, hflip=True, rot=True):        # if the patch_size = None the augment will be error because the image has filp and image 2 no flip the batch will be wrong         hflip = hflip and random.random() < 0.5        vflip = rot and random.random() < 0.5        rot90 = rot and random.random() < 0.5        if self.light_change == 1 and random.random() < 0.5:            light_gain = [-55, -45, -20, -10, 10, 20, 45, 55]            light = random.choice(light_gain)        else:            light = 0        def _augment(img):            if hflip: img = img[:, ::-1]            if vflip: img = img[::-1, :]            if rot90: img = img.transpose(1, 0)            if light != 0:                imgf = img.astype(float)  # numpy  20   np.float -> float                imgf_gain = imgf + light                imgf_gain_high = (imgf_gain > 254)                imgf_gain[imgf_gain_high] = 255                img = imgf_gain.astype(int)  # numpy  20   np.int -> int            return img        return _augment(image), _augment(mask)